%% Check if a path does not contain directory traversal sequences.
is_path_safe(Path, Result) :-
    ((\+ atom_concat('..', _, Path) , \+ atom_concat('/..', _, Path)) -> Result = true ; Result = false).

%% Check if a filename is not a hidden dotfile.
is_visible_file(Filename, Result) :-
    (\+ atom_concat('.', _, Filename) -> Result = true ; Result = false).

%% Check if a path component starts with a dot (hidden file/directory).
is_hidden_path(Path, Result) :-
    (atom_concat('.', _, Path) -> Result = true ; Result = false).

%% Check if a path contains .. traversal sequences.
has_path_traversal(Path, Result) :-
    (atom_concat('..', _, Path) -> Result = true ; Result = false).

%% Check if a command starts with a known safe prefix (ls, cat, grep, echo).
is_safe_command(Cmd, Result) :-
    (((atom_concat('ls', _, Cmd) ; atom_concat('cat', _, Cmd)) ; (atom_concat('grep', _, Cmd) ; atom_concat('echo', _, Cmd))) -> Result = true ; Result = false).

